var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……대답하실 필요 없습니다.","JPN":"……お答えする必要はございません。","ENG":"There's no need to answer that.","TWN":"……你不需要回答。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자세한 것은 제가 말씀드리죠. 당신들은 제 손님이니까요.","JPN":"詳しいことは私から伝えます。あなた方は私のお客様ですから。","ENG":"I will tell you all the details. You are my guests, after all.","TWN":"就由我來代為回答吧，畢竟你們是我的客人！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"서, 성녀님! 어째서 이런 곳에?!","JPN":"せ、聖女様！　どうしてこんな所に！？","ENG":"Y-your Holiness! What brings you here?!","TWN":"是…聖女！您怎麼會出現在這裡？！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그보다 손님이라니……. 설마 저들에 대해 알고 계십니까?","JPN":"それよりお客様だとは……あの者たちをご存知でしょうか？","ENG":"And did you say guests? Does Your Holiness know something about them?","TWN":"您說他們是客人……難道您認識他們嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"외람되오나, 저들은 정체 모를 이방인입니다.","JPN":"僭越ながら申し上げますが、彼らは正体不明の異邦人です。","ENG":"With all due respect, they are complete strangers from a foreign land.","TWN":"恕小的直言，他們是身分不明的外邦人。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"마왕의 하수인일 가능성도 아직 완전히 배제할 수 없습니다. 자리를 피하십시오.","JPN":"魔王の手下である可能性もまだ否定できません。どうかこの場から離れてください。","ENG":"We have yet to rule out the possibility they serve the Demon Lord. Please get yourself to safety.","TWN":"目前也尚未完全排除他們是魔王手下的可能性，還請您不要插手。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아뇨. 저들은 마왕의 하수인이 아닙니다.","JPN":"いいえ、彼らは魔王の手下ではありません。","ENG":"No. They do not serve the Demon Lord.","TWN":"不，他們不是魔王的手下。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 건 오래 전에 모두 사라졌으니까요.","JPN":"そんなものは遠い昔にすべて消えていますから。","ENG":"Because all of that has long expired.","TWN":"根本沒這回事。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예? 그게 무슨 말씀이신지……?","JPN":"はい？　それはどういう……","ENG":"What? I beg your pardon, but…","TWN":"什麼？那是什麼意思……？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 님께서 자리를 비우신 바람에 위장 마법의 효과가 약해졌나 보군요.","JPN":"アレン様のご不在で偽装魔法の効果が弱まったようですね。","ENG":"It appears the concealment spell has grown weak with Sir Allen's absence.","TWN":"艾倫離開後，偽裝術的法力似乎變弱了。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그렇지 않다면, 외부인들이 이 <color=#ffd34c>성역의 잔재</color>에 발을 들일 수 있을 리 없으니까요.","JPN":"そうでなければ、外部の人間がこの<color=#ffd34c>聖域の残滓</color>に足を踏み入れることができるはずがありません。","ENG":"Otherwise, outsiders would not be able to set foot into these <color=#ffd34c>remains of sanctuary</color>.","TWN":"否則外面的人怎麼可能進到<color=#ffd34c>聖域幻境</color>呢？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알렌 선생님을 알고 있어?","JPN":"アレン先生を知っているの？","ENG":"You know Allen? Birmingham?","TWN":"你認識艾倫老師？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선생님을 만나게 해 줘. 우린 그 사람과 할 얘기가 있어.","JPN":"先生に会わせて。私たちはあの人に話がある。","ENG":"Please let us meet him. We have something to discuss with him.","TWN":"讓我見他，我們有話要跟他說！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"돌아가세요. 저주받은 늑대여.","JPN":"帰りなさい、呪われた狼よ。","ENG":"Please leave. Ye Cursed Wolf.","TWN":"受詛咒的狼，你請回吧！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은 아직 이 신성한 땅에 다다를 자격을 갖추지 못했습니다.","JPN":"あなたはまだこの神聖な地に辿り着く資格を備えておりません。","ENG":"You have yet to prove yourself worthy of reaching this sacred ground.","TWN":"你還沒有資格踏上這塊神聖的土地。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"본래는 허락 없이 이 땅에 발을 들인 것만으로도 크나큰 죄를 범한 것입니다.","JPN":"本来は許可無しでこの地に足を踏み入れただけでも大罪なのです。","ENG":"Normally, merely setting foot here without permission would constitute a grave crime.","TWN":"原本未經許可就擅自踏上這塊土地是要重重治罪的。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지금은 그저 나의 구원자님께서 징벌을 명하지 않으셨기에 묵인해 드리고 있을 뿐이죠.","JPN":"今はただ、我が救世主様が懲罰を命じられていないので黙認しているにすぎません。","ENG":"I've merely turned a blind eye because my Savior has not ordered your punishment.","TWN":"現在只是因為我的救贖者大人尚未下令懲處，才暫時放任你們。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안하지만 그냥은 못 돌아가겠어.","JPN":"悪いけど、このまま引き返すことはできない。","ENG":"Sorry, but I can't just leave like this.","TWN":"很抱歉，我們無法就這樣回去！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};